import React from "react";
import { Link } from "react-router-dom";

import "./NotFound.css";

function NotFound() {

    return (

        <div className="not-found">

            <h1>

                404

            </h1>

            <h2>

                Page Not Found

            </h2>

            <p>

                The page you are looking for does not exist.

            </p>

            <Link

                to="/"

                className="not-found__button"

            >

                Back To Home

            </Link>

        </div>

    );

}

export default NotFound;
